func TestNormalize(t *testing.T) {
	tests := []struct {
		input string
		want  string
	}{
		// Basic lowercase
		{"Harvard University", "harvard university"},

		// "The " prefix removal
		{"The Ohio State University", "ohio state university"},
		{"the ohio state university", "ohio state university"},
		// "The" in the middle should be kept
		{"University of the Pacific", "university of the pacific"},

		// Diacritics stripping
		{"École Polytechnique", "ecole polytechnique"},
		{"Université de Montréal", "universite de montreal"},
		{"São Paulo University", "sao paulo university"},

		// Punctuation removal
		{"St. John's University", "st johns university"},
		{"Texas A&M University", "texas a m university"},
		{"Purdue University-Main Campus", "purdue university main campus"},
		{"University of Wisconsin–Madison", "university of wisconsin madison"},

		// Whitespace collapse
		{"  Stanford   University  ", "stanford university"},
		{"MIT", "mit"},

		// Hyphen in name becomes space
		{"Indiana University-Bloomington", "indiana university bloomington"},

		// Already normalized
		{"ohio state university", "ohio state university"},

		// Empty string
		{"", ""},

		// Numbers preserved
		{"California State University San Marcos", "california state university san marcos"},
	}

	for _, tc := range tests {
		got := Normalize(tc.input)
		if got != tc.want {
			t.Errorf("Normalize(%q) = %q, want %q", tc.input, got, tc.want)
		}
	}
}
